import { Menu, X } from 'lucide-react';
import { useState } from 'react';
import { Link, useLocation } from 'react-router-dom';

const navItems = [
  { label: 'Features', to: '/#features' },
  { label: 'Modules', to: '/#modules' },
  { label: 'Contact', to: '/contact' },
  { label: 'Pricing', to: '/#pricing' },
];

const Navbar = ({ isPublic = false }) => {
  const [mobileOpen, setMobileOpen] = useState(false);
  const location = useLocation();

  const isActive = (to) => {
    if (to.includes('#')) {
      return location.pathname === to.split('#')[0] && location.hash === `#${to.split('#')[1]}`;
    }
    return location.pathname === to;
  };

  return (
    <header className="sticky top-0 z-50 border-b border-surface bg-bg/95 backdrop-blur">
      <nav className="mx-auto flex max-w-7xl items-center justify-between px-4 py-4 sm:px-6 lg:px-8">
        {/* Logo */}
        <Link to="/" className="flex items-center gap-2">
          <div className="flex h-8 w-8 items-center justify-center rounded-lg bg-brand text-sm font-bold text-white">
            ⚡
          </div>
          <span className="text-lg font-semibold text-text-primary">ContextOS</span>
        </Link>

        {/* Desktop nav */}
        <div className="hidden items-center gap-8 md:flex">
          {navItems.map((item) => (
            <Link
              key={item.to}
              to={item.to}
              className={`text-sm font-medium transition ${
                isActive(item.to)
                  ? 'text-brand'
                  : 'text-text-secondary hover:text-text-primary'
              }`}
            >
              {item.label}
            </Link>
          ))}
        </div>

        {/* Auth buttons */}
        <div className="hidden items-center gap-3 md:flex">
          {isPublic ? (
            <>
              <Link
                to="/login"
                className="text-sm font-medium text-text-secondary transition hover:text-text-primary"
              >
                Sign in
              </Link>
              <Link
                to="/register"
                className="rounded-lg bg-brand px-4 py-2 text-sm font-medium text-white transition hover:bg-brand-dark"
              >
                Get started
              </Link>
            </>
          ) : (
            <Link
              to="/dashboard"
              className="text-sm font-medium text-brand transition hover:text-brand-dark"
            >
              Dashboard
            </Link>
          )}
        </div>

        {/* Mobile menu button */}
        <button
          type="button"
          className="md:hidden"
          onClick={() => setMobileOpen(!mobileOpen)}
        >
          {mobileOpen ? (
            <X size={20} className="text-text-primary" />
          ) : (
            <Menu size={20} className="text-text-primary" />
          )}
        </button>
      </nav>

      {/* Mobile menu */}
      {mobileOpen ? (
        <div className="border-t border-surface bg-bg2 px-4 py-4 sm:px-6">
          <div className="space-y-3">
            {navItems.map((item) => (
              <Link
                key={item.to}
                to={item.to}
                onClick={() => setMobileOpen(false)}
                className="block text-sm font-medium text-text-secondary hover:text-text-primary"
              >
                {item.label}
              </Link>
            ))}
            <div className="border-t border-surface pt-3">
              {isPublic ? (
                <>
                  <Link
                    to="/login"
                    className="block py-2 text-sm font-medium text-text-secondary hover:text-text-primary"
                  >
                    Sign in
                  </Link>
                  <Link
                    to="/register"
                    className="block rounded-lg bg-brand px-4 py-2 text-center text-sm font-medium text-white transition hover:bg-brand-dark"
                  >
                    Get started
                  </Link>
                </>
              ) : (
                <Link
                  to="/dashboard"
                  className="block text-sm font-medium text-brand hover:text-brand-dark"
                >
                  Dashboard
                </Link>
              )}
            </div>
          </div>
        </div>
      ) : null}
    </header>
  );
};

export default Navbar;

import { ArrowRight, BarChart3, Bell, Cable, LayoutDashboard, Settings, Wallet } from 'lucide-react';
import { Link } from 'react-router-dom';
import Button from '../components/Button';
import Footer from '../components/Footer';
import Navbar from '../components/Navbar';

const modulesList = [
  {
    icon: LayoutDashboard,
    title: 'Dashboard',
    description: 'Get real-time insights and metrics across all your data sources.',
    slug: 'dashboard',
  },
  {
    icon: BarChart3,
    title: 'Query Engine',
    description: 'Build complex queries with an intuitive interface and AI assistance.',
    slug: 'query',
  },
  {
    icon: Cable,
    title: 'Integrations',
    description: 'Connect with 100+ data sources and APIs seamlessly.',
    slug: 'integrations',
  },
  {
    icon: BarChart3,
    title: 'Knowledge Graph',
    description: 'Visualize relationships and explore data connections intuitively.',
    slug: 'graph',
  },
  {
    icon: Bell,
    title: 'Notifications',
    description: 'Stay updated with real-time alerts and notifications.',
    slug: 'notifications',
  },
  {
    icon: Wallet,
    title: 'Billing',
    description: 'Manage subscriptions, usage, and payments with ease.',
    slug: 'billing',
  },
  {
    icon: Settings,
    title: 'Team Management',
    description: 'Collaborate with your team and manage permissions.',
    slug: 'team',
  },
  {
    icon: LayoutDashboard,
    title: 'Organization',
    description: 'Organize workspaces and manage organizational structure.',
    slug: 'org',
  },
];

const Home = () => {
  return (
    <div className="min-h-screen bg-bg text-text-primary">
      <Navbar isPublic />

      {/* Hero */}
      <section className="border-b border-surface px-4 py-20 sm:px-6 lg:px-8">
        <div className="mx-auto max-w-7xl text-center">
          <h1 className="text-5xl font-semibold tracking-tight md:text-6xl leading-tight">
            Unified Data <span className="text-brand">Intelligence</span> Platform
          </h1>
          <p className="mt-6 text-lg text-text-secondary leading-relaxed">
            Connect all your data sources, visualize relationships, and collaborate with your team.
            <br />
            Built for developers. Designed for teams.
          </p>
          <div className="mt-8 flex flex-col items-center justify-center gap-4 sm:flex-row">
            <Link to="/register">
              <Button className="px-6 py-3 text-base">Get Started Free</Button>
            </Link>
            <Link
              to="/contact"
              className="inline-flex items-center gap-2 text-sm font-medium text-brand hover:text-brand-dark transition"
            >
              Request Demo
              <ArrowRight size={16} />
            </Link>
          </div>
        </div>
      </section>

      {/* Features */}
      <section id="features" className="border-b border-surface px-4 py-16 sm:px-6 lg:px-8">
        <div className="mx-auto max-w-7xl">
          <div className="text-center mb-12">
            <p className="text-xs font-bold uppercase tracking-widest text-text-secondary">
              CAPABILITIES
            </p>
            <h2 className="mt-2 text-3xl font-semibold">Everything you need</h2>
          </div>

          <div className="grid grid-cols-1 gap-6 md:grid-cols-2 lg:grid-cols-4">
            {[
              {
                title: 'Real-time sync',
                desc: 'Keep all your data synchronized across integrations.',
              },
              {
                title: 'AI-powered queries',
                desc: 'Generate complex queries using natural language.',
              },
              {
                title: 'Visual graphs',
                desc: 'Understand data relationships at a glance.',
              },
              {
                title: 'Team collab',
                desc: 'Work together with granular permission controls.',
              },
            ].map((feat, idx) => (
              <div key={idx} className="rounded-lg border border-surface bg-bg2 p-6">
                <h3 className="font-medium text-text-primary">{feat.title}</h3>
                <p className="mt-2 text-sm text-text-secondary">{feat.desc}</p>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Modules */}
      <section id="modules" className="border-b border-surface px-4 py-16 sm:px-6 lg:px-8">
        <div className="mx-auto max-w-7xl">
          <div className="text-center mb-12">
            <p className="text-xs font-bold uppercase tracking-widest text-text-secondary">
              MODULES
            </p>
            <h2 className="mt-2 text-3xl font-semibold">8 Integrated Tools</h2>
          </div>

          <div className="grid grid-cols-1 gap-6 md:grid-cols-2 lg:grid-cols-4">
            {modulesList.map((module) => {
              const Icon = module.icon;
              return (
                <div
                  key={module.slug}
                  className="rounded-lg border border-surface bg-bg2 p-6 transition hover:border-brand hover:bg-bg3"
                >
                  <Icon size={24} className="text-brand" />
                  <h3 className="mt-4 font-medium text-text-primary">{module.title}</h3>
                  <p className="mt-2 text-sm text-text-secondary">{module.description}</p>
                </div>
              );
            })}
          </div>
        </div>
      </section>

      {/* Pricing */}
      <section id="pricing" className="border-b border-surface px-4 py-16 sm:px-6 lg:px-8">
        <div className="mx-auto max-w-7xl">
          <div className="text-center mb-12">
            <p className="text-xs font-bold uppercase tracking-widest text-text-secondary">
              PRICING
            </p>
            <h2 className="mt-2 text-3xl font-semibold">Simple, Transparent Pricing</h2>
          </div>

          <div className="grid grid-cols-1 gap-6 md:grid-cols-3">
            {[
              {
                name: 'Starter',
                price: 'Free',
                features: [
                  '5 team members',
                  '100 AI queries/month',
                  'Basic integrations',
                  'Community support',
                ],
              },
              {
                name: 'Pro',
                price: '$49',
                period: '/month',
                features: [
                  'Unlimited members',
                  '5,000 AI queries/month',
                  'All integrations',
                  'Priority support',
                  'Advanced analytics',
                ],
                highlighted: true,
              },
              {
                name: 'Enterprise',
                price: 'Custom',
                features: [
                  'Everything in Pro',
                  'Unlimited AI queries',
                  'Custom integrations',
                  'Dedicated support',
                  'SLA guarantee',
                ],
              },
            ].map((plan, idx) => (
              <div
                key={idx}
                className={`rounded-lg border p-6 transition ${
                  plan.highlighted
                    ? 'border-brand bg-bg3'
                    : 'border-surface bg-bg2 hover:border-surface2'
                }`}
              >
                <h3 className="text-lg font-medium">{plan.name}</h3>
                <div className="mt-4">
                  <span className="text-3xl font-semibold">{plan.price}</span>
                  {plan.period && (
                    <span className="text-sm text-text-secondary">{plan.period}</span>
                  )}
                </div>
                <ul className="mt-6 space-y-3">
                  {plan.features.map((feat, fidx) => (
                    <li key={fidx} className="flex items-center gap-2 text-sm text-text-secondary">
                      <div className="h-1 w-1 rounded-full bg-brand" />
                      {feat}
                    </li>
                  ))}
                </ul>
                <Button className="mt-6 w-full" variant={plan.highlighted ? 'primary' : 'secondary'}>
                  {plan.name === 'Enterprise' ? 'Contact Us' : 'Get Started'}
                </Button>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* CTA */}
      <section className="border-b border-surface bg-bg2 px-4 py-16 sm:px-6 lg:px-8">
        <div className="mx-auto max-w-3xl text-center">
          <h2 className="text-3xl font-semibold">Ready to get started?</h2>
          <p className="mt-4 text-text-secondary">
            Join teams worldwide using ContextOS to unlock insights from their data.
          </p>
          <div className="mt-8 flex flex-col items-center justify-center gap-4 sm:flex-row">
            <Link to="/register">
              <Button>Create Free Account</Button>
            </Link>
            <Link
              to="/contact"
              className="text-sm font-medium text-brand hover:text-brand-dark transition"
            >
              Schedule a demo
            </Link>
          </div>
        </div>
      </section>

      <Footer />
    </div>
  );
};

export default Home;
